THE CLAIM:
{
 "title": "NL geo share too high: Dutch ban redirects new-build revenue",
 "narrative": "The model sets the Netherlands at 28% of geographic share, based on a 2025 installed-capacity snapshot. But a pre-launch entrant sells into new build-outs, and since early 2024 the Netherlands bans new hyperscale data centres outside two municipalities. Weighting Year-1 sales at a 0.28 NL share points the venture at the geography commissioning the least new capacity, so the Year-1 number is skewed toward the wrong market.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Since early 2024 the Netherlands bans new large hyperscale sites.",
   "refs": [
    "digest:geo-NL#c7",
    "digest:geo-NL#c8"
   ]
  },
  {
   "step": "propagation",
   "text": "New fit-out flow shifts to Germany, Poland and CEE instead.",
   "refs": [
    "digest:geo-NL#c0",
    "digest:geo-NL#c16",
    "ledger:geo.NL"
   ]
  },
  {
   "step": "model-impact",
   "text": "Year-1 demand tracks new capacity, so NL's 0.28 overstates it.",
   "refs": [
    "ledger:geo.PL",
    "ledger:geo.other",
    "profile:Stage"
   ]
  }
 ],
 "falsifier": "DDA's 2026 State of the Dutch Data Centers showing NL colocation additions at or above 28% of total CE-7 additions for the year.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "Challenges in the Dutch Data Center Market",
   "sourceType": "industry-report",
   "publisher": "Greenberg Traurig LLP",
   "date": "2024-03",
   "excerpt": "an amendment of the decree...that entered into force on 1 January 2024, no hyperscale data centers are [permitted]",
   "url": "https://www.gtlaw.com/en/insights/2024/3/challenges-in-the-dutch-data-center-market",
   "attached": true
  },
  {
   "title": "DDA: stroomvoorziening bepaalt tempo Nederlandse datacentergroei",
   "sourceType": "industry-report",
   "publisher": "MSP Business (citing DDA State of the Dutch Data Centers 2026)",
   "date": "2026-06-08",
   "excerpt": "Tot 2031 verwacht de DDA een gemiddelde jaarlijkse groei van twaalf procent, naar 2,8 gigawatt. Die groei blijft desondanks achter bij het Europese gemiddelde.",
   "url": "https://mspbusiness.com/markt-en-strategie/dda-stroomvoorziening-bepaalt-tempo-nederlandse-datacentergroei/",
   "attached": true
  },
  {
   "title": "Why Flexibility Has Become Key to Success in EMEA Data Centre Markets",
   "sourceType": "industry-report",
   "publisher": "DC Byte",
   "date": "2026-06-04",
   "excerpt": "Pipeline across major markets has slowed down...The major beneficiaries of this shift have been emerging markets, such as the Nordics, Southern Europe and the Middle East",
   "url": "https://www.dcbyte.com/news-blogs/why-flexibility-has-become-key-to-success-in-emea-data-centre-markets/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.NL",
  "label": "Netherlands",
  "kind": "estimated",
  "value": 0.28,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "geography",
  "dimensionValue": "NL",
  "sensitivityRange": {
   "low": 0.24,
   "high": 0.31
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "NL colo 951 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.276 → 0.28 (normalized)",
   "crossCheck": "Dutch Data Center Association: national colo 924 MW (2024) — consistent scale"
  },
  "provenance": {
   "rationale": "Statista and the national association agree within ~3% → inferred, triangulated."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Netherlands 951 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "Ten years of State of the Dutch Data Centers",
    "sourceType": "industry-report",
    "publisher": "Dutch Data Center Association",
    "date": "2024",
    "excerpt": "In 2024, the total colocation capacity reached 924 megawatts... the Amsterdam Metropolitan Area still accounts for approximately 70% of colocation capacity.",
    "attached": true
   }
  ]
 },
 {
  "id": "geo.PL",
  "label": "Poland",
  "kind": "estimated",
  "value": 0.07,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "geography",
  "dimensionValue": "PL",
  "sensitivityRange": {
   "low": 0.06,
   "high": 0.1
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "PL colo 228 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.066 → 0.07 (normalized)",
   "crossCheck": "Installed-IT-load method (Mordor 660 MW, 2025) → ~0.10 — scopes diverge, band widened"
  },
  "provenance": {
   "rationale": "Colo vs installed-load scopes diverge ~1.5x for the fast-growing Polish base → inferred, wide band.",
   "promotionPath": "Adopt one scope (PMR commercial-DC series) across all CE countries → narrow band."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Poland 228 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "Poland Data Center Market — size & installed IT load",
    "sourceType": "industry-report",
    "publisher": "Mordor Intelligence",
    "date": "2025",
    "excerpt": "Base Year Market Size (2025): 660 megawatt installed IT load, growing to 998.34 MW by 2030 (7.28% CAGR).",
    "attached": true
   }
  ]
 },
 {
  "id": "geo.other",
  "label": "Other CE",
  "kind": "estimated",
  "value": 0.03,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": "geography",
  "dimensionValue": "other",
  "sensitivityRange": null,
  "funnelActive": true,
  "derivation": {
   "method": "Residual bucket",
   "expression": "HU 18 + RO 27 + SK 14 + SI 6 + HR 17 + BG 32 = 114 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.033 → 0.03 (residual, normalized)"
  },
  "provenance": {
   "rationale": "Sum of small itemised markets from one source; fast CEE growth (Romania +40% of upcoming CEE capacity) adds uncertainty.",
   "promotionPath": "Break out RO/HU explicitly once either exceeds ~5% of the CE base."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Hungary 18, Romania 27, Slovakia 14, Slovenia 6, Croatia 17, Bulgaria 32 MW of colocation IT power in 2025.",
    "attached": true
   }
  ]
 }
]

